var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이터니움 주입, <color=#ffd34c>먹의 편린</color> 99개 전체 활성화.","JPN":"エタニウム注入、<color=#ffd34c>墨の片鱗</color>99個全体活性化。","ENG":"Injecting Eternium. All ninety-nine <color=#ffd34c>Ink Fragments</color> activated.","TWN":"永恆之金注入，<color=#ffd34c>墨片</color>99個整體啟動。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"에너지 파형의 진로 방향 가시화 진행… 진로 교차점 선별.","JPN":"エネルギー波形の進路方向可視化を進行……進路交差点を選別。","ENG":"Visualizing energy waveform trajectories… Identifying intersection points.","TWN":"能量波形軌道可視化進行中…軌道交叉點篩選。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"클러스터링 패턴 분석 완료.","JPN":"クラスタリングパターン分析完了。","ENG":"Clustering pattern analysis complete.","TWN":"聚類模式分析完成。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"총 여덟 개의 진로 교차점을 발견했습니다.","JPN":"合計8つの進路交差点が見つかりました。","ENG":"Eight trajectory intersections detected.","TWN":"發現總共八個軌道交叉點。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"교차점이 여덟 곳이나 된다고…? 보물이 있는 좌표는 하나라고 하지 않았어?!","JPN":"交差点が8つも……？　宝がある座標は1個だけじゃなかったのかよ！？","ENG":"Eight trajectory intersections…? I thought there was only one coordinate with the treasure!","TWN":"交叉點有八個…？不是說寶物所在的座標只有一個嗎？！"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"패턴 분석은 틀리지 않았어. 그렇다면 일단 전부 뚫어보는 수 밖에.","JPN":"パターン分析は間違ってない。ならば、とりあえず全部確かめるしかない。","ENG":"The pattern analysis isn't wrong. Which means we just have to break through all of them.","TWN":"模式分析沒有錯。那看來只能全部試試看了。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하지만 여덟 곳을 전부 확인하기엔 여력이 부족해요!","JPN":"でも8か所を全部確かめるのは無理です！","ENG":"But we don't have the resources to check all eight!","TWN":"但是要確認八個地方，我們的能力不足！"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"차원 균열이 더 심해지면 탈출도 불가능할 테니, 사실상 기회는 한 번 뿐이라고요.","JPN":"次元の亀裂がもっと進んだら脱出もできないし、実質チャンスは1回だけなんです。","ENG":"If the dimensional rift gets any worse, we might not even be able to escape. We've only got one shot at this.","TWN":"次元裂縫如果更加嚴重，連逃脫都不可能，實際上只有一次機會。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다들 알고 있겠지만, 허수 공간의 좌표는 계속 고정되어 있지 않아.","JPN":"皆も知っていると思うが、虚数空間の座標はいつまでも固定されてはいない。","ENG":"As you all know, nothing stays in place in the imaginary space.","TWN":"大家應該都知道，虛數空間的座標不是固定不變的。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"떠나면 지금까지 준비해온 것들을 전부 잃는 거야.","JPN":"離れれば、今まで準備してきたすべてが水の泡になるんだ。","ENG":"Once we leave, everything we've prepared up until now goes down the drain.","TWN":"一旦離開，我們至今為止所做的準備都會白費。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"뭘 고르든 서두르는 게 좋을 거다. 살아 돌아가기 싫은 게 아니라면 말이지.","JPN":"どれを選ぼうが急いだほうがいいぞ。生きて帰りたいならな。","ENG":"Then pick one fast. Unless you're not planning on making it back alive.","TWN":"無論選擇哪一個，都最好快一點。如果你們不想死在這裡的話。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"여기까지 와서 운에 모든 걸 맡겨야 하다니, 곤란하게 됐네요.","JPN":"ここまで来て運任せとは、困ったものですね。","ENG":"All this way, just to leave it to luck. What a mess.","TWN":"都到這裡了，卻要將一切交給運氣，真是傷腦筋。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"네가 선택해라, 꼬마.","JPN":"お前が選べ、ガキ。","ENG":"Your choice, kid.","TWN":"你來選，小鬼。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제가… 고르라고요?","JPN":"僕が……ですか？","ENG":"You… want me to decide?","TWN":"我…來選？"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그것도 혹시 육익의 계략인가요?","JPN":"もしかしてそれも六翼の計略ですか？","ENG":"Wait, don't tell me this is another one of Six Wings' schemes.","TWN":"這也是六翼的計謀嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"널 이용하는 계략이라고 볼 수도 있지. 하지만 속임수 같은 건 아니야.","JPN":"お前を利用する計略とみてもいい。だが、騙すつもりはない。","ENG":"You could call it a scheme, sure. But it's not a trick.","TWN":"也可以說這是利用你的計謀。但這不是騙局。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"잠깐 정도라면 나 혼자서도 녀석을 막을 수는 있어.","JPN":"少しの間なら、私一人でもやつを足止めできる。","ENG":"I can hold it off for a little while on my own.","TWN":"我一個人可以暫時擋住那個傢伙。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그러니 빨리 다녀오라고.","JPN":"だから早く行ってこい。","ENG":"So hurry and go.","TWN":"所以快去吧。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"미리 말씀드리지만, 제 운은 별로 좋은 편이 아녜요.","JPN":"先に言っておきますが、僕の運はあまりいい方ではありませんよ。","ENG":"Just a heads up, but I've never been that lucky.","TWN":"我先說了，我的運氣不太好。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"운에 맡기는 게 아냐.","JPN":"運に任せるわけじゃない。","ENG":"It's not about luck.","TWN":"這不是交給運氣。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"네 마음 향하는 길이… 곧 운명이니까.","JPN":"お前の心が惹かれる道が……運命だ。","ENG":"The path your heart chooses… is what decides fate.","TWN":"你心之所向的道路…就是命運。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"…소란스럽군.","JPN":"……騒がしいな。","ENG":"…What's all this ruckus.","TWN":"…好吵。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"여긴 어디인가?","JPN":"ここはどこだ？","ENG":"Where is this place?","TWN":"這裡是什麼地方？"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 나는 누구인가?","JPN":"某は誰だ？","ENG":"And who am I?","TWN":"而我是誰？"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"까마득한 어둠, 그 한복판에 갇혀 있다면 당연히 들게 될 의문을… 아주 오랜만에 갖게 되는군.","JPN":"深い闇、その中に閉じ込められていれば当然持つようになる疑問が……実に久しぶりに湧いてきた。","ENG":"It's been a long time since I last asked myself the question anyone would have… when trapped in the heart of endless darkness.","TWN":"被困在無邊的黑暗中，產生這樣的疑問是理所當然的…真是好久沒有了。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};